mapper.select:
SELECT op_log_id, op_id, op_name, dept_name, title, business_type, operate_type, method, status, request_method, url, ip, location, error_msg, op_time FROM sm_op_log WHERE 1=1
AND title LIKE CONCAT('%', #{query.title},'%')
AND op_name LIKE CONCAT('%', #{query.operName},'%')
AND op_time >= #{query.startTime}
AND op_time <= #{query.endTime}
ORDER BY op_time DESC
